## Description
实现 `scheduler::BlockLoadTask`，一个带软件预取（software prefetch）的分块个体状态批量读取器，通过提前预取下一块数据消除数据管道中的 cache miss 停顿，提升 ISG（warp）内个体状态处理的内存带宽利用率。

```cpp
namespace world::scheduler {
  template <typename StateT, size_t BlockSize = 128>
  class BlockLoadTask {
  public:
    BlockLoadTask(const StateT* src, size_t count);
    // 加载当前块并预取下一块
    span<const StateT> load_and_prefetch();
    bool has_next() const;
  private:
    void prefetch_next_block();  // __builtin_prefetch / PTX prefetch
    const StateT* src_;
    size_t offset_ = 0, count_;
  };
}

// 用法：ISG 内无停顿个体状态批量处理
BlockLoadTask<IndividualState> loader(states, count);
while (loader.has_next()) {
    auto block = loader.load_and_prefetch();  // 预取下一块，消除等待
    process_block(block);
}
```

