## Description
为 `scheduler::CRoutine` 的分段归约（segmented reduce）任务添加编译期固定步长（compile-time fixed stride）的调度调优策略，允许在编译期绑定最优步长，避免运行时步长参数化带来的分支开销，提升分段归约的 ISG（warp）执行效率。

```cpp
namespace world::scheduler {
  // 编译期固定步长策略
  template <size_t Stride>
  struct FixedStridePolicy {
    static constexpr size_t stride = Stride;
    // 编译期确定的步长，无运行时分支
  };

  template <typename StateT, typename ReduceOp,
            typename StridePol = FixedStridePolicy<32>>
  class SegmentedReduceTask {
  public:
    void execute(span<const StateT> input, span<StateT> output, ReduceOp op) {
      constexpr size_t S = StridePol::stride;
      // 编译期展开，无运行时步长判断
      for (size_t i = 0; i < input.size(); i += S) {
        warp_reduce<S>(input.subspan(i, S), output[i/S], op);
      }
    }
  };
}
```

